insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'A car travels at 60 km/h for 3 hours. What distance does it cover?', 'एक car 60 km/h की चाल से 3 घंटे चलती है। दूरी कितनी होगी?', 'Distance = Speed × Time = 60 × 3 = 180 km.', 'The three quantities are linked by D = S × T. Given any two, the third follows. Keep units consistent — here km/h × h = km. Mixing km/h with minutes silently produces unit errors; convert first if needed.', 'Distance = Speed × Time = 60 × 3 = 180 km।', 'तीनों राशियाँ D = S × T से जुड़ी हैं। दो दी हों तो तीसरी निकलती है। Units consistent रखें: km/h × h = km। km/h को minutes के साथ mix करने पर silent unit error; पहले convert करें।', 'EASY', array['speed-distance','basic','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '180 km', '180 km', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '20 km', '20 km', false, 'Divided instead of multiplied: 60/3 = 20. Formula is distance = speed × time, not speed ÷ time.', 'Multiply की जगह divide किया: 60/3 = 20। Formula: distance = speed × time।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '63 km', '63 km', false, 'Added speed and time treating them as like quantities: 60 + 3 = 63. Speed and time are different dimensions.', 'Speed और time को जोड़ दिया: 60 + 3 = 63। ये अलग dimensions हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '240 km', '240 km', false, 'Used 4 hours instead of 3: 60 × 4 = 240. Misread the duration.', '3 घंटे की जगह 4 घंटे लगा दिए: 60 × 4 = 240।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'A cyclist covers 45 km in 3 hours. Find her average speed.', 'एक cyclist 3 घंटे में 45 km की दूरी तय करती है। उसकी average speed क्या है?', 'Speed = Distance / Time = 45/3 = 15 km/h.', 'Average speed is total distance divided by total time. For a single leg at constant pace, it equals the instantaneous speed. For multi-leg journeys at different paces, average ≠ (sum of speeds)/n — it''s still total distance / total time.', 'Speed = Distance / Time = 45/3 = 15 km/h।', 'Average speed = total distance / total time। एक ही pace वाली यात्रा में यह instantaneous speed के बराबर होती है। Multi-leg यात्रा में average ≠ (speeds का sum)/n — total distance / total time ही है।', 'EASY', array['speed-distance','average-speed','basic','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '15 km/h', '15 km/h', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '135 km/h', '135 km/h', false, 'Multiplied distance by time: 45 × 3 = 135. Speed = distance/time, not distance × time.', 'Distance × time कर दिया: 45 × 3 = 135। Speed = distance/time होता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '42 km/h', '42 km/h', false, 'Subtracted time from distance: 45 − 3 = 42. Wrong operation — distance and time aren''t subtractable quantities.', 'Distance में से time घटाया: 45 − 3 = 42। Distance और time घटाए नहीं जाते।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '1/15 km/h', '1/15 km/h', false, 'Inverted the formula: computed time/distance = 3/45 = 1/15. Speed is the direct ratio, not its reciprocal.', 'Formula उल्टी लगाई: time/distance = 3/45 = 1/15 निकाला। Speed direct ratio है, उल्टी नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'Convert 54 km/h to m/s.', '54 km/h को m/s में बदलिए।', 'Multiply by 5/18 to go km/h → m/s: 54 × 5/18 = 270/18 = 15 m/s.', '1 km = 1000 m and 1 h = 3600 s, so 1 km/h = 1000/3600 = 5/18 m/s. Memorize this fraction and its reciprocal 18/5 for rapid two-way conversion in the exam. Errors come from dropping either the distance or the time part of the conversion.', 'km/h → m/s के लिए 5/18 से गुणा करें: 54 × 5/18 = 270/18 = 15 m/s।', '1 km = 1000 m और 1 h = 3600 s, अतः 1 km/h = 5/18 m/s। यह fraction और इसका reciprocal 18/5 याद रखें — exam में जल्दी convert करने के लिए।', 'EASY', array['speed-distance','unit-conversion','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '15 m/s', '15 m/s', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '194.4 m/s', '194.4 m/s', false, 'Multiplied by 3.6 instead of dividing: 54 × 3.6 = 194.4. The factor 18/5 (= 3.6) goes m/s → km/h; the inverse is 5/18.', '3.6 से भाग देने की जगह multiply किया: 54 × 3.6 = 194.4। 3.6 m/s → km/h के लिए है, उल्टी दिशा में 5/18 लगेगा।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '9 m/s', '9 m/s', false, 'Divided by 6 (approximated the factor as 6): 54/6 = 9. Correct conversion factor is 18/5 = 3.6.', '6 से भाग दिया (factor को 6 मान लिया): 54/6 = 9। सही factor 18/5 = 3.6।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '150 m/s', '150 m/s', false, 'Converted km → m but skipped the h → s step: 54 × 1000 / 360 = 150 (divided by 360 instead of 3600).', 'km → m किया पर h → s miss: 54 × 1000 / 360 = 150 (3600 की जगह 360 से भाग)।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 3, 'A train 120 m long is running at 72 km/h. How long does it take to cross a stationary pole?', 'एक 120 m लंबी train 72 km/h की चाल से चल रही है। एक खड़े pole को पार करने में कितना समय लगेगा?', 'Speed = 72 × 5/18 = 20 m/s. Distance = length of train = 120 m (pole is a point). Time = 120/20 = 6 s.', 'When a train crosses a stationary point (pole, person, signal), the distance covered equals the train''s own length — the front reaches the point, then the whole train must pass. Convert speed to m/s so the units align with the length in metres.', 'Speed = 72 × 5/18 = 20 m/s। Distance = train की length = 120 m (pole point है)। Time = 120/20 = 6 sec।', 'Stationary point (pole, person, signal) को cross करते समय covered distance = train की length। Speed को m/s में बदलें ताकि length (m में) के साथ units match हों।', 'EASY', array['speed-distance','train','length-crossing','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '6 seconds', '6 सेकंड', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '1.67 seconds', '1.67 सेकंड', false, 'Skipped km/h → m/s conversion: computed 120/72 = 1.67 treating 72 as m/s.', 'km/h → m/s conversion छोड़ दी: 120/72 = 1.67 निकाला, 72 को m/s मान लिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '8 seconds', '8 सेकंड', false, 'Used speed 54 km/h = 15 m/s from a memorized example: 120/15 = 8. Actual speed 72 km/h = 20 m/s.', 'Memorize किया हुआ example (54 km/h = 15 m/s) लगा दिया: 120/15 = 8। असली speed 72 km/h = 20 m/s।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '2 seconds', '2 सेकंड', false, 'Converted 72 km/h to 20 m/s correctly but divided 120 by 60 instead of 20 (slipped a decimal): 120/60 = 2.', '72 km/h → 20 m/s ठीक, पर 120 को 20 की जगह 60 से भाग दिया: 120/60 = 2।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 4, 'A bus travels from city A to city B at 40 km/h and returns at 60 km/h by the same route. Find the average speed for the whole journey.', 'एक bus city A से B तक 40 km/h से और वापस same route पर 60 km/h से लौटती है। पूरी यात्रा की average speed क्या है?', 'Equal distance each way: avg speed = 2ab/(a+b) = 2 × 40 × 60 / 100 = 4800/100 = 48 km/h.', 'When equal DISTANCES are travelled at different speeds, the time spent at the slower speed is more, dragging the average below the arithmetic mean. The formula 2ab/(a+b) is the harmonic mean of the two speeds — derived from total distance / total time where each leg has equal distance d: total time = d/a + d/b, total distance = 2d, ratio = 2ab/(a+b).', 'Equal distance each way: avg speed = 2ab/(a+b) = 2 × 40 × 60 / 100 = 48 km/h।', 'Equal DISTANCES पर अलग speeds से चलने पर slower speed पर ज़्यादा time लगता है — average arithmetic mean से कम आता है। Formula 2ab/(a+b) दोनों speeds का harmonic mean है: total time = d/a + d/b, total distance = 2d, ratio = 2ab/(a+b)।', 'MEDIUM', array['speed-distance','average-speed','harmonic-mean','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '50 km/h', '50 km/h', false, 'Arithmetic mean: (40 + 60)/2 = 50. Arithmetic mean of speeds is only correct when equal TIME is spent at each speed, not equal DISTANCE.', 'Arithmetic mean: (40 + 60)/2 = 50। यह तभी सही है जब हर speed पर equal TIME हो, equal DISTANCE नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '48 km/h', '48 km/h', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '52 km/h', '52 km/h', false, 'Picked a value midway but biased high — used a weighted average with wrong weights (bias towards 60).', 'Midway value लगाई पर 60 की ओर झुकी — wrong weights वाला weighted average।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '24 km/h', '24 km/h', false, 'Used (40 × 60)/(40 + 60) without the × 2: 2400/100 = 24. Harmonic mean formula requires the 2× in the numerator for equal distances.', '(40 × 60)/(40 + 60) में × 2 भूल गए: 2400/100 = 24। Harmonic mean formula में numerator 2× होता है (equal distances के लिए)।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 5, 'A man walks at 5 km/h for 2 hours and then runs at 10 km/h for 1 hour. What is his average speed for the whole journey?', 'एक आदमी 5 km/h से 2 घंटे चलता है और फिर 10 km/h से 1 घंटा दौड़ता है। पूरी यात्रा की average speed क्या है?', 'Total distance = 5 × 2 + 10 × 1 = 10 + 10 = 20 km. Total time = 2 + 1 = 3 h. Average = 20/3 = 6.67 km/h.', 'Average speed is always total distance divided by total time — never a plain arithmetic mean of the speeds. When times are the weights (equal-time legs), arithmetic mean coincides; otherwise, compute distance per leg and sum, then divide by the sum of times.', 'Total distance = 5 × 2 + 10 × 1 = 10 + 10 = 20 km। Total time = 2 + 1 = 3 h। Average = 20/3 = 6.67 km/h।', 'Average speed हमेशा total distance / total time — speeds का plain arithmetic mean नहीं। Equal-time legs में arithmetic mean match कर जाता है; अन्यथा per-leg distance निकालकर जोड़ें, फिर total time से भाग दें।', 'MEDIUM', array['speed-distance','average-speed','weighted-average','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '7.5 km/h', '7.5 km/h', false, 'Used arithmetic mean of the two speeds: (5 + 10)/2 = 7.5. That''s correct only if equal TIME is split and weights are equal — here times are 2 h and 1 h, not equal.', 'दोनों speeds का arithmetic mean: (5 + 10)/2 = 7.5। यह केवल equal times पर सही है, यहाँ 2 h और 1 h हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '6.67 km/h', '6.67 km/h', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '8.33 km/h', '8.33 km/h', false, 'Swapped the weights: used (5 × 1 + 10 × 2)/3 = 25/3 = 8.33. Man walks 2 h and runs 1 h, so weights are 2 on 5 and 1 on 10.', 'Weights उलट दिए: (5 × 1 + 10 × 2)/3 = 25/3 = 8.33 निकाला। 2 h × 5 और 1 h × 10 सही है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '15 km/h', '15 km/h', false, 'Added the total distances (10 + 10 = 20) and divided by ''number of legs'' = 2: 20/2 = 10. Then added 5 km/h. Muddled total distance/total time path.', 'Total distances जोड़कर (10 + 10 = 20) legs 2 से भाग किया: 20/2 = 10, फिर 5 जोड़ दिया। Total distance / total time की सीधी राह छोड़ दी।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 6, 'Two trains of lengths 150 m and 100 m run in opposite directions on parallel tracks at 40 km/h and 50 km/h respectively. How long do they take to cross each other completely?', '150 m और 100 m की दो trains parallel tracks पर विपरीत दिशा में क्रमशः 40 km/h और 50 km/h से चल रही हैं। एक-दूसरे को पूरी तरह cross करने में कितना समय लगेगा?', 'Relative speed (opposite direction) = 40 + 50 = 90 km/h = 90 × 5/18 = 25 m/s. Distance to cover = 150 + 100 = 250 m. Time = 250/25 = 10 s.', 'When two trains cross each other, the ''distance'' for the crossing event is the sum of their lengths — the rear of one must pass the rear of the other. Relative speed ADDS for opposite directions and SUBTRACTS for same direction (the observer sits on one train).', 'Relative speed (विपरीत दिशा) = 40 + 50 = 90 km/h = 90 × 5/18 = 25 m/s। Crossing distance = 150 + 100 = 250 m। Time = 250/25 = 10 sec।', 'दो trains cross करते समय ''distance'' दोनों lengths का sum होता है — एक की पिछली end दूसरी की पिछली end को pass करनी होती है। Relative speed विपरीत दिशा में जुड़ती है, same direction में घटती है।', 'MEDIUM', array['speed-distance','train','relative-speed','opposite-direction','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '10 seconds', '10 सेकंड', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '22.5 seconds', '22.5 सेकंड', false, 'Used only one train''s speed 40 km/h = 11.11 m/s: 250/11.11 = 22.5 s. In opposite-direction crossing, relative speed is the SUM (90 km/h = 25 m/s), not either single speed.', 'केवल एक train की speed 40 km/h = 11.11 m/s लगाई: 250/11.11 = 22.5 s। विपरीत दिशा में relative = SUM (90 km/h = 25 m/s)।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '90 seconds', '90 सेकंड', false, 'Subtracted the speeds (50 − 40 = 10 km/h = 2.78 m/s) instead of adding: 250/2.78 = 90. Subtraction is for same-direction, not opposite-direction.', 'Speeds घटा दिए (50 − 40 = 10 km/h = 2.78 m/s): 250/2.78 = 90। घटाना same-direction के लिए है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '6 seconds', '6 सेकंड', false, 'Used only one train''s length (150 m) with correct relative speed 25 m/s: 150/25 = 6 s. Crossing event requires the SUM of both lengths = 250 m.', 'केवल एक train की length (150 m) लगाई (relative speed 25 m/s सही): 150/25 = 6 s। Crossing में दोनों lengths का SUM = 250 m लगता है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 7, 'A boat goes 24 km downstream in 3 hours and 16 km upstream in 4 hours. Find the speed of the boat in still water.', 'एक boat 3 घंटे में 24 km downstream और 4 घंटे में 16 km upstream तय करती है। still water में boat की speed क्या है?', 'Downstream speed = 24/3 = 8 km/h. Upstream speed = 16/4 = 4 km/h. Boat in still water = (8 + 4)/2 = 6 km/h.', 'Let boat speed in still water = b, stream speed = s. Downstream = b + s; upstream = b − s. Adding gives 2b; subtracting gives 2s. So b = (downstream + upstream)/2 and s = (downstream − upstream)/2. Both are halves — of the sum and the difference respectively.', 'Downstream = 24/3 = 8 km/h। Upstream = 16/4 = 4 km/h। Still water boat = (8 + 4)/2 = 6 km/h।', 'Boat speed still water = b, stream speed = s मानें। Downstream = b + s, upstream = b − s। Joड़ें: 2b; घटाएँ: 2s। अतः b = (downstream + upstream)/2, s = (downstream − upstream)/2।', 'MEDIUM', array['speed-distance','boat-stream','still-water-speed','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '6 km/h', '6 km/h', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '8 km/h', '8 km/h', false, 'Reported only the downstream speed (24/3 = 8) as the still-water speed. Still-water speed is the AVERAGE of downstream and upstream speeds.', 'Downstream speed (24/3 = 8) को ही still-water speed मान लिया। Still-water speed downstream और upstream का AVERAGE होती है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '4 km/h', '4 km/h', false, 'Reported only the upstream speed (16/4 = 4). Still-water speed is midway between downstream and upstream, not either alone.', 'केवल upstream speed (16/4 = 4) दे दी। Still-water speed downstream और upstream के बीच midway होती है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '2 km/h', '2 km/h', false, 'Computed stream speed (8 − 4)/2 = 2 instead of boat speed. Stream speed = half the DIFFERENCE; boat speed = half the SUM.', 'Stream speed (8 − 4)/2 = 2 निकाल दी, boat की speed नहीं। Stream = आधा DIFFERENCE; boat = आधा SUM।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 8, 'A person walks to his office at 5 km/h and reaches 10 minutes late. If he walks at 6 km/h, he reaches 5 minutes early. Find the distance to the office.', 'एक व्यक्ति 5 km/h से office जाता है तो 10 min late पहुँचता है। 6 km/h से जाए तो 5 min early पहुँचता है। office की दूरी क्या है?', 'Let distance = d km. Time at 5 km/h = d/5; at 6 km/h = d/6. The time difference is (10 + 5) = 15 min = 0.25 h (late to early). So d/5 − d/6 = 0.25 ⇒ d/30 = 0.25 ⇒ d = 7.5 km.', 'When two speeds give different arrival statuses (late vs early), both refer to the same ''on-time'' clock. Time at the slow speed minus time at the fast speed equals total ''late + early'' offset. That gap is the difference of two travel times for the same distance.', 'Distance = d km मानें। Time @ 5 km/h = d/5; @ 6 km/h = d/6। Time difference = 10 + 5 = 15 min = 0.25 h। d/5 − d/6 = 0.25 ⇒ d/30 = 0.25 ⇒ d = 7.5 km।', 'दो speeds से अलग arrival statuses (late vs early) आएँ, तो दोनों ''on-time'' clock से नापे जाते हैं। Slow speed पर time − fast speed पर time = कुल ''late + early'' gap — same distance के दो travel times का अंतर।', 'MEDIUM', array['speed-distance','late-early','two-speeds','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '7.5 km', '7.5 km', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '5 km', '5 km', false, 'Multiplied the slow speed 5 km/h by the total late-early offset (15 min = 0.25 h) × 4 = 5. Distance requires subtracting two travel times d/5 − d/6 = 0.25.', 'Slow speed 5 × 0.25 × 4 = 5 लगाया। सही: d/5 − d/6 = 0.25 से d निकलता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '5.5 km', '5.5 km', false, 'Averaged the two speeds: (5 + 6)/2 = 5.5, and reported it as distance (wrong units — km/h is not km). The d-equation is d(1/5 − 1/6) = 0.25.', 'दोनों speeds का average: (5 + 6)/2 = 5.5 को distance दे दिया (unit गलत — km/h km नहीं है)।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '10 km', '10 km', false, 'Used gap in hours incorrectly: wrote time offset as 15 h instead of 15 min (skipped /60), then 5 × 2 = 10. Must convert minutes to hours (0.25 h).', 'Time offset को 15 min की जगह 15 h मान लिया (/60 भूल गए), फिर 5 × 2 = 10। 15 min = 0.25 h चाहिए।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 9, 'A train passes a 200 m long platform in 25 seconds and a 150 m long platform in 20 seconds. Find the length of the train.', 'एक train 200 m के platform को 25 sec में और 150 m के platform को 20 sec में cross करती है। Train की length क्या है?', 'Let train length = L, speed = v (m/s). (L + 200) = 25v and (L + 150) = 20v. Subtract: 50 = 5v ⇒ v = 10 m/s. Then L + 200 = 250 ⇒ L = 50 m.', 'Crossing a platform, the train must cover its own length PLUS the platform length. Two separate crossings with the same train (and the same constant speed) give two linear equations in (L, v); subtracting eliminates L to expose v, then back-substitute for L. Always write the sum (L + platform) as the covered distance — missing the train''s own length is the classic slip.', 'Train length = L, speed = v (m/s) मानें। (L + 200) = 25v, (L + 150) = 20v। घटाएँ: 50 = 5v ⇒ v = 10 m/s। L + 200 = 250 ⇒ L = 50 m।', 'Platform cross करते समय train को खुद की length PLUS platform length तय करनी होती है। एक ही train की दो crossings से दो linear equations (L, v) मिलते हैं — घटाकर L eliminate करें, v निकालें, फिर L। ''खुद की length भूलना'' classic गलती है।', 'MEDIUM', array['speed-distance','train','platform-length','two-equations','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '50 m', '50 m', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '100 m', '100 m', false, 'Averaged the two platform lengths: (200 + 150)/2 = 175, then subtracted a plausible-looking 75 to get 100. Not derived from the two-equation system.', 'Platform lengths का average: (200 + 150)/2 = 175, फिर कोई 75 घटाकर 100 कर दिया। Two-equation system से निकालना था।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '250 m', '250 m', false, 'Took the total distance of the first crossing (train+platform = 200 + train_length) and assigned it as train length: mistook the sum for the train length alone.', 'पहली crossing की total distance (200 + train length) को train length मान लिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '75 m', '75 m', false, 'Subtracted the two platform lengths and halved: (200 − 150)/2 = 25, rough-scaled to 75. The equations give exactly 50, not this midway guess.', 'Platform lengths को घटाकर आधा: (200 − 150)/2 = 25, फिर बढ़ाकर 75 कर दिया। Equations से सटीक 50 निकलता है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'A and B start from the same point in the same direction. A walks at 4 km/h and B at 6 km/h. After how many hours will B be 5 km ahead of A?', 'A और B एक ही जगह से एक ही दिशा में निकलते हैं। A की speed 4 km/h, B की 6 km/h। कितने घंटों बाद B, A से 5 km आगे होगा?', 'Relative speed (same direction) = 6 − 4 = 2 km/h. Time to open a 5 km gap = 5/2 = 2.5 hours.', 'When two objects move in the same direction, the faster one opens up a gap at a rate equal to the DIFFERENCE of their speeds. In opposite directions the rate is the SUM. Always ask which frame of reference the problem wants (catch-up vs meet vs overtake).', 'Relative speed (same direction) = 6 − 4 = 2 km/h। 5 km का gap खुलने में time = 5/2 = 2.5 घंटे।', 'Same direction में तेज़ वाली object gap को speeds के अंतर की दर से खोलती है। विपरीत direction में यह दर sum होती है। Catch-up/meet/overtake — पहले तय करें।', 'MEDIUM', array['speed-distance','relative-speed','same-direction','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '2.5 hours', '2.5 घंटे', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '1.25 hours', '1.25 घंटे', false, 'Divided gap 5 by only A''s speed 4: 5/4 = 1.25. Used one train''s speed instead of the relative speed (6 − 4 = 2).', 'Gap 5 को केवल A की speed 4 से भाग दिया: 5/4 = 1.25। Relative speed (6 − 4 = 2) लगानी थी।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '1 hour', '1 घंटा', false, 'Added the speeds: 4 + 6 = 10; then 5/10 = 0.5, doubled for ''return trip'' assumption = 1. Relative speed for same direction SUBTRACTS.', 'Speeds जोड़े (4 + 6 = 10): 5/10 = 0.5, × 2 = 1 किया। Same direction में घटाते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '0.5 hour', '0.5 घंटा', false, 'Used gap 5 over SUM of speeds 10 (opposite-direction formula): 5/10 = 0.5. Same direction requires DIFFERENCE (2 km/h).', 'Gap 5 को SUM 10 से भाग दिया (opposite-direction formula): 0.5। Same direction में DIFFERENCE (2 km/h) लगती है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 11, 'A man rows 20 km downstream in 2 hours and the same distance upstream in 5 hours. Find the speed of the stream.', 'एक व्यक्ति 20 km downstream 2 घंटे में और same distance upstream 5 घंटे में तय करता है। Stream की speed क्या है?', 'Downstream = 20/2 = 10 km/h. Upstream = 20/5 = 4 km/h. Stream = (10 − 4)/2 = 3 km/h.', 'Downstream − Upstream = 2 × stream (the boat speed cancels), so stream speed = half the difference. Similarly (downstream + upstream)/2 gives the boat''s still-water speed. Memorize the ''half-sum, half-difference'' pair — exam questions will ask for one or the other.', 'Downstream = 20/2 = 10 km/h। Upstream = 20/5 = 4 km/h। Stream = (10 − 4)/2 = 3 km/h।', 'Downstream − Upstream = 2 × stream (boat speed cancel), अतः stream = आधा difference। Still-water boat = आधा sum। ''आधा-sum, आधा-difference'' pair याद रखें।', 'MEDIUM', array['speed-distance','boat-stream','stream-speed','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '3 km/h', '3 km/h', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '7 km/h', '7 km/h', false, 'Reported still-water speed (10 + 4)/2 = 7 instead of stream speed. Still-water = boat; stream = half the DIFFERENCE.', 'Still-water speed (10 + 4)/2 = 7 दे दी, stream नहीं। Boat = आधा SUM; stream = आधा DIFFERENCE।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '6 km/h', '6 km/h', false, 'Used full difference (10 − 4 = 6) without halving. Stream speed = HALF the difference of downstream and upstream.', 'Full difference (10 − 4 = 6) दे दी, आधा नहीं किया। Stream = आधा DIFFERENCE।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '2.5 km/h', '2.5 km/h', false, 'Used upstream/2 = 4/2 = 2; interpreted ''stream'' as half of upstream speed. Correct is half of (downstream − upstream).', 'Upstream/2 = 4/2 = 2 लगा दिया (थोड़ा adjust करके 2.5)। सही: आधा (downstream − upstream) = (10 − 4)/2 = 3।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 12, 'A train crosses a man walking in the same direction at 6 km/h in 10 seconds. If the speed of the train is 60 km/h, find the length of the train.', 'एक train same direction में 6 km/h से चलते आदमी को 10 sec में cross करती है। Train की speed 60 km/h हो तो Train की length क्या है?', 'Relative speed (same direction) = 60 − 6 = 54 km/h = 54 × 5/18 = 15 m/s. Length = 15 × 10 = 150 m.', 'Crossing a moving observer is framed in the observer''s frame of reference: the effective speed is the RELATIVE speed. For same direction subtract, for opposite add. The crossing distance equals the train''s length because the observer is a point.', 'Relative speed (same direction) = 60 − 6 = 54 km/h = 54 × 5/18 = 15 m/s। Length = 15 × 10 = 150 m।', 'चलते observer को cross करना observer के frame में देखें: effective speed = RELATIVE speed। Same direction में घटाएँ, विपरीत में जोड़ें। Crossing distance = train की length (observer point है)।', 'MEDIUM', array['speed-distance','train','relative-speed','same-direction','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '150 m', '150 m', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '166.67 m', '166.67 m', false, 'Used train speed 60 km/h alone (ignored the walker''s 6 km/h): 60 × 5/18 × 10 = 600/18 × 10 = 166.67 m. Same direction requires relative speed 60 − 6.', 'Train की 60 km/h अकेली लगाई (walker की 6 km/h छोड़ दी): 60 × 5/18 × 10 = 166.67 m। Same direction में relative 60 − 6 लगेगी।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '100 m', '100 m', false, 'Used walker''s speed 6 km/h as relative (read the question as ''crosses walker at 6 km/h relative''): 6 × 5/18 × 10 × 6 = 100. Arithmetic slip compounded with reading error.', 'Walker की 6 km/h को relative मान लिया: 6 × 5/18 × 10 × 6 = 100। Reading error के साथ arithmetic slip।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '183.33 m', '183.33 m', false, 'Added speeds instead of subtracting: 60 + 6 = 66 km/h → 66 × 5/18 × 10 = 183.33 m. Addition is for opposite direction; same direction requires subtraction.', 'Speeds जोड़े (60 + 6 = 66 km/h): 66 × 5/18 × 10 = 183.33 m। जोड़ना opposite direction के लिए है, same के लिए घटाते हैं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 13, 'A runner can complete a 1 km race in 4 minutes. How many metres does he run in 12 seconds?', 'एक runner 1 km दौड़ 4 मिनट में पूरी करता है। 12 sec में वह कितने metre दौड़ता है?', 'Speed = 1000 m / 240 s = 25/6 m/s. Distance in 12 s = 25/6 × 12 = 50 m.', 'Always normalize to a common unit system before scaling. Here: convert 1 km to 1000 m and 4 min to 240 s to get speed in m/s, then multiply by the target 12 s. Staying in mixed units (km and minutes) almost always leads to a factor-60 or factor-1000 slip.', 'Speed = 1000 m / 240 s = 25/6 m/s। 12 sec में distance = 25/6 × 12 = 50 m।', 'Scaling से पहले units को एकसमान करें। यहाँ 1 km = 1000 m, 4 min = 240 s से speed m/s में, फिर × 12 sec। Mixed units में रहने पर 60 या 1000 का factor slip होता है।', 'MEDIUM', array['speed-distance','unit-conversion','ratio','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '50 m', '50 m', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '48 m', '48 m', false, 'Used 1 km / 4 min = 0.25 km/min = 250 m/min → 250/5 = 50, but split into 48 via rounding 4 min = 240 s error pathway.', '1 km/4 min = 250 m/min; 12 s/60 = 0.2 min; 250 × 0.2 = 50, पर ratio चक्कर में 48 निकाल लिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '3 m', '3 m', false, 'Divided distance 1 by time 4: 1/4 = 0.25, then scaled by 12 = 3. Did not convert km to metres before scaling.', 'Distance 1 को time 4 से भाग दिया: 0.25 × 12 = 3। km को metre में बदलना भूल गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '100 m', '100 m', false, 'Used 4 min = 4 × 60 s = 240 s, ratio 1000 m / 240 s = 25/6 m/s, then 25/6 × 24 = 100. Used 24 s instead of 12 s.', '4 min = 240 s, 1000/240 = 25/6 m/s, 12 की जगह 24 s लगा दिए → 25/6 × 24 = 100।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 14, 'Two trains leave stations A and B simultaneously towards each other at 50 km/h and 70 km/h. They meet after 3 hours. What is the distance between A and B?', 'दो trains stations A और B से एक-दूसरे की ओर एक साथ 50 km/h और 70 km/h से चलती हैं। 3 घंटे में मिलती हैं। A और B के बीच की दूरी क्या है?', 'Closing speed = 50 + 70 = 120 km/h. Distance = closing speed × time = 120 × 3 = 360 km.', 'Two objects moving toward each other close their gap at a rate equal to the SUM of their speeds. The initial gap is closed in time × sum, which equals the distance between their starting points. Symmetric idea to same-direction problems where the closing rate is the DIFFERENCE.', 'Closing speed = 50 + 70 = 120 km/h। Distance = closing × time = 120 × 3 = 360 km।', 'दो objects एक-दूसरे की ओर आ रहे हों तो gap speeds के SUM की दर से बंद होता है। Initial gap = time × sum = starting points के बीच की distance। Same-direction में closing rate = DIFFERENCE।', 'MEDIUM', array['speed-distance','relative-speed','opposite-direction','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '360 km', '360 km', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '60 km', '60 km', false, 'Subtracted the speeds (70 − 50 = 20 km/h) and multiplied by 3: 20 × 3 = 60. Opposite-direction relative speed is the SUM, not difference.', 'Speeds घटाए (70 − 50 = 20) × 3 = 60। विपरीत दिशा में relative = SUM।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '180 km', '180 km', false, 'Used one train''s speed only: 60 × 3 = 180 (averaged 50 and 70 then × 3). The correct formula uses the combined 120 km/h closing speed.', 'एक ही train की speed लगाई: 60 × 3 = 180 (50 और 70 का average × 3)। सही 120 km/h closing speed × 3।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '120 km', '120 km', false, 'Reported the closing speed (50 + 70 = 120 km/h) as the distance — forgot to multiply by the 3 hours.', 'Closing speed (50 + 70 = 120 km/h) को distance मान लिया — × 3 घंटे नहीं किया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 15, 'A car driver covers a distance in 4 hours at 60 km/h. If he increases his speed by 20 km/h, how long will the same journey take?', 'एक car driver 60 km/h से 4 घंटे में एक दूरी तय करता है। अगर वह speed 20 km/h बढ़ा दे, तो वही यात्रा कितने समय में पूरी होगी?', 'Distance = 60 × 4 = 240 km. New speed = 80 km/h. New time = 240 / 80 = 3 h. Shortcut: time ∝ 1/speed for fixed distance, so new_time/4 = 60/80 = 3/4, new_time = 3 h.', 'For a fixed distance, time and speed are inversely proportional. Doubling speed halves time; a 1/3 speed increase drops time by 1/4 (because 3/4 × 4 = 3). Never subtract speed absolutely and expect a linear time change — use the ratio.', 'Distance = 60 × 4 = 240 km। नई speed = 80 km/h। नया time = 240/80 = 3 h। Shortcut: fixed distance पर time ∝ 1/speed, new_time/4 = 60/80 = 3/4, new_time = 3 h।', 'Fixed distance पर time और speed inversely proportional हैं। Double speed → half time; 1/3 बढ़ी speed → time 1/4 कम (3/4 × 4 = 3)। Speed को absolute घटाकर linear time change की अपेक्षा न करें — ratio लगाएँ।', 'MEDIUM', array['speed-distance','constant-distance','inverse-proportion','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '3 hours', '3 घंटे', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '3.5 hours', '3.5 घंटे', false, 'Subtracted 0.5 h from 4 h treating the 20 km/h jump as roughly a 1/8 speed increase: 4 − 0.5 = 3.5. Actual ratio 60/80 = 3/4 gives new time = 3 h.', '4 − 0.5 = 3.5 किया (20 km/h jump को ~1/8 बढ़त मानकर)। सही ratio 60/80 = 3/4 ⇒ 3 घंटे।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '2.67 hours', '2.67 घंटे', false, 'Applied additive subtraction: 20/60 × 4 = 1.33 h reduction → 4 − 1.33 = 2.67. Time scaling is MULTIPLICATIVE (× 3/4 = 3), not additive.', 'Additive subtraction: 20/60 × 4 = 1.33 घटाकर 4 − 1.33 = 2.67 किया। Time scaling multiplicative है (× 3/4 = 3), additive नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '4.8 hours', '4.8 घंटे', false, 'Multiplied 4 × 1.2 = 4.8 (treated 20 km/h increase as 20% of time added). Distance is constant — speed up ⇒ time DOWN, not up.', '4 × 1.2 = 4.8 किया (20 km/h बढ़त को 20% time increase मान लिया)। Distance constant ⇒ speed ↑ → time ↓।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 16, 'A man travels from X to Y at 30 km/h and returns at 40 km/h. If the total journey took 7 hours, find the distance between X and Y.', 'एक आदमी X से Y तक 30 km/h और वापस 40 km/h से लौटता है। कुल यात्रा 7 घंटे चली। X और Y के बीच की दूरी क्या है?', 'Let distance = d. Time going = d/30, returning = d/40. Total: d/30 + d/40 = 7 ⇒ d × (4 + 3)/120 = 7 ⇒ 7d/120 = 7 ⇒ d = 120 km.', 'Same distance in both directions but different speeds ⇒ add the two travel times (not average them). The equation d/v₁ + d/v₂ = T collapses to d × (v₁ + v₂)/(v₁ × v₂) = T, i.e., d = T × v₁ × v₂ / (v₁ + v₂). That''s T × half the harmonic mean.', 'Distance = d। जाते time = d/30, वापस = d/40। Total: d/30 + d/40 = 7 ⇒ d × 7/120 = 7 ⇒ d = 120 km।', 'दोनों दिशाओं में same distance पर अलग speeds ⇒ travel times जोड़ें (average नहीं)। Equation d/v₁ + d/v₂ = T से d = T × v₁ × v₂ /(v₁ + v₂) — T × आधा harmonic mean।', 'HARD', array['speed-distance','round-trip','two-equations','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '120 km', '120 km', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '122.5 km', '122.5 km', false, 'Used arithmetic-mean speed (30 + 40)/2 = 35 km/h × (7/2) = 122.5 km for the one-way leg. Equal-distance legs need the HARMONIC mean for average speed, not arithmetic.', 'Arithmetic mean (30 + 40)/2 = 35 × (7/2) = 122.5 km एक leg के लिए। Equal-distance में HARMONIC mean चाहिए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '240 km', '240 km', false, 'Reported the ROUND-TRIP total distance (2 × 120 = 240) as the one-way distance. Question asks for one-way X to Y.', 'Round-trip total (2 × 120 = 240) को one-way मान लिया। Question one-way X से Y पूछ रहा है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '70 km', '70 km', false, 'Added speeds 30 + 40 = 70 and dropped the time factor entirely. Dimensions break — km/h alone is not km.', 'Speeds जोड़े (30 + 40 = 70), time factor छोड़ दिया। Dimensions गलत — km/h अकेले km नहीं है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 17, 'A train running at 45 km/h crosses a bridge in 30 seconds. If the length of the bridge is 250 m, find the length of the train.', 'एक train 45 km/h से चलते हुए एक bridge को 30 sec में cross करती है। Bridge की length 250 m हो तो Train की length क्या है?', 'Speed in m/s = 45 × 5/18 = 12.5 m/s. Total distance covered = 12.5 × 30 = 375 m. Length of train = total − bridge = 375 − 250 = 125 m.', 'Crossing a bridge, the covered distance is train''s length + bridge''s length. Given time and speed, compute total distance, then subtract the bridge length to isolate the train''s length.', 'Speed m/s में = 45 × 5/18 = 12.5 m/s। Total covered = 12.5 × 30 = 375 m। Train length = total − bridge = 375 − 250 = 125 m।', 'Bridge cross करते समय covered distance = train length + bridge length। Time और speed से total distance निकालकर bridge length घटाएँ।', 'MEDIUM', array['speed-distance','train','bridge-length','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '125 m', '125 m', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '375 m', '375 m', false, 'Reported total distance covered (= train length + bridge length = 375) as the train length alone. Forgot to subtract the bridge 250.', 'Total covered distance (= train length + bridge = 375) को train length मान लिया। Bridge 250 घटाना भूल गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '250 m', '250 m', false, 'Assumed train length equals bridge length (250). They are independent — train length comes from total distance − bridge.', 'Train length को bridge length (250) के बराबर मान लिया। ये independent हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '200 m', '200 m', false, 'Used memorized speed 54 km/h = 15 m/s instead of converting 45 km/h: 15 × 30 = 450 total, 450 − 250 = 200. Speed 45 km/h = 12.5 m/s gives 375 total, 125 train.', 'Memorize की हुई 54 km/h = 15 m/s लगाई (45 km/h = 12.5 m/s चाहिए): 15 × 30 = 450 − 250 = 200। सही: 12.5 × 30 = 375 − 250 = 125।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 18, 'Two pipes fill a tank in 12 hours and 18 hours respectively. If both are opened together, how long will they take to fill the tank?', 'दो pipes एक tank को क्रमशः 12 घंटे और 18 घंटे में भरती हैं। दोनों एक साथ खोलने पर tank कितने समय में भरेगा?', 'Combined rate = 1/12 + 1/18 = 3/36 + 2/36 = 5/36 tanks per hour. Time = 36/5 = 7.2 hours.', 'Rate problems parallel speed problems one-for-one: if pipe A fills the tank in a hours and B in b hours, their combined rate is 1/a + 1/b (tanks per hour), and the combined time is ab/(a+b). The formula is the harmonic mean''s close cousin — same structure as ''equal distance, two speeds'' average speed.', 'Combined rate = 1/12 + 1/18 = 5/36 tanks/hour। Time = 36/5 = 7.2 घंटे।', 'Rate problems speed problems की तरह: pipe A तt a घंटे में, B b घंटे में भरे तो combined rate = 1/a + 1/b, combined time = ab/(a+b)। ''Equal distance, two speeds'' average speed जैसा structure।', 'MEDIUM', array['speed-distance','rate-work','pipes-cisterns','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '7.2 hours', '7.2 घंटे', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '15 hours', '15 घंटे', false, 'Averaged the two times (12 + 18)/2 = 15. Pipe rates add when they work in parallel; the resulting time is always LESS than either individual time.', 'Times का average (12 + 18)/2 = 15 निकाल दिया। Parallel pipes की rates जुड़ती हैं — resulting time हर एक से कम होता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '30 hours', '30 घंटे', false, 'Added the two times (12 + 18 = 30). Additive time is only for sequential work — for parallel, rates add not times.', 'Times जोड़ दिए (12 + 18 = 30)। Sequential में time जुड़ता है, parallel में rate जुड़ती है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '6 hours', '6 घंटे', false, 'Half of the smaller time (12/2 = 6). The combined rate formula is 1/T = 1/12 + 1/18 giving T = 36/5 = 7.2, not 6.', 'छोटे time का आधा (12/2 = 6)। सही formula 1/T = 1/12 + 1/18 ⇒ T = 36/5 = 7.2।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 19, 'A boat''s downstream speed is 15 km/h and the speed of the stream is 3 km/h. Find the time taken to travel 36 km upstream.', 'एक boat की downstream speed 15 km/h है और stream की speed 3 km/h है। Upstream 36 km जाने में कितना time लगेगा?', 'Boat speed in still water = downstream − stream = 15 − 3 = 12 km/h. Upstream speed = 12 − 3 = 9 km/h. Time = 36/9 = 4 hours.', 'To find the upstream speed when only downstream and stream are given: first recover the boat''s still-water speed (= downstream − stream), then upstream = still-water − stream. Equivalently, upstream = downstream − 2 × stream (because the stream aids downstream and opposes upstream, so it switches sign twice).', 'Boat still-water speed = downstream − stream = 15 − 3 = 12 km/h। Upstream = 12 − 3 = 9 km/h। Time = 36/9 = 4 घंटे।', 'Downstream और stream दी हों, तो पहले boat still-water (= downstream − stream), फिर upstream = still-water − stream। समकक्ष: upstream = downstream − 2 × stream।', 'MEDIUM', array['speed-distance','boat-stream','upstream','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '4 hours', '4 घंटे', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '2.4 hours', '2.4 घंटे', false, 'Used downstream speed 15 km/h: 36/15 = 2.4. Question asks UPSTREAM (which is 9 km/h).', 'Downstream speed 15 km/h लगाई: 36/15 = 2.4। Question UPSTREAM (9 km/h) पूछ रहा है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '12 hours', '12 घंटे', false, 'Used stream speed 3 km/h: 36/3 = 12. Stream alone doesn''t move the boat — upstream speed = boat − stream = 12 − 3 = 9, not 3.', 'Stream speed 3 km/h लगाई: 36/3 = 12। Stream अकेले boat को नहीं चलाती — upstream = boat − stream = 12 − 3 = 9।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '3 hours', '3 घंटे', false, 'Added stream speed to downstream (15 + 3 = 18) → 36/18 = 2, then adjusted to 3. Upstream = downstream − 2 × stream = 15 − 6 = 9; time = 36/9 = 4.', 'Downstream में stream जोड़ा (15 + 3 = 18) → 36/18 = 2, फिर 3 कर दिया। सही Upstream = downstream − 2 × stream = 9, time = 4 घंटे।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 20, 'A train running at ''x'' km/h crosses a platform 300 m long in 24 seconds, and a pole in 9 seconds. Find the speed of the train in km/h.', 'एक train ''x'' km/h पर 300 m के platform को 24 sec में और एक pole को 9 sec में cross करती है। Train की speed km/h में ज्ञात कीजिए।', 'Let train length = L, speed = v (m/s). Pole: L = 9v. Platform: L + 300 = 24v. Subtract: 300 = 15v ⇒ v = 20 m/s = 20 × 18/5 = 72 km/h.', 'The two crossings share the same train length L and same speed v. Subtracting the pole equation from the platform equation eliminates L, isolating v from the 300 m difference in covered distance and the 15 s difference in time. This ''eliminate by subtraction'' pattern is the workhorse of two-crossing problems.', 'Train length = L, speed = v (m/s) मानें। Pole: L = 9v। Platform: L + 300 = 24v। घटाएँ: 300 = 15v ⇒ v = 20 m/s = 72 km/h।', 'दोनों crossings में same L और v। Platform-pole घटाने से L cancel, 300 m extra और 15 s extra से v निकल आती है। यह ''घटाकर eliminate'' pattern two-crossing problems का basic trick है।', 'HARD', array['speed-distance','train','two-equations','platform-length','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '72 km/h', '72 km/h', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '45 km/h', '45 km/h', false, 'Used platform 300 m / 24 s = 12.5 m/s = 45 km/h, treating the crossing distance as just the platform. The crossing also needs the train''s own length.', 'Platform 300 m / 24 s = 12.5 m/s = 45 km/h लगा दिया — crossing distance में train की length भूल गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '120 km/h', '120 km/h', false, 'Used pole time × large speed guess: 300 m / 9 s = 33.33 m/s = 120 km/h. Pole crossing gives train-length/9 = speed, not platform/9.', '300/9 = 33.33 m/s = 120 km/h लगाया। Pole crossing train-length/9 = speed देता है, 300/9 नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '80 km/h', '80 km/h', false, 'Used 300 m / (24 − 9) = 20 m/s = 72 km/h and bumped to 80 by adding a fictitious ''slack''. The correct value is exactly 72, not 80.', '300/(24−9) = 20 m/s = 72 km/h निकाला पर ''slack'' जोड़कर 80 कर दिया। सही value 72 है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 21, 'A man can row 9 km/h in still water. He takes twice as long to row upstream as downstream. Find the speed of the stream.', 'एक व्यक्ति still water में 9 km/h row कर सकता है। वह upstream में downstream से दोगुना समय लेता है। Stream की speed क्या है?', 'Let stream = s. Downstream speed = 9 + s; upstream = 9 − s. Time ratio upstream:downstream = 2:1 ⇒ (9 + s)/(9 − s) = 2 ⇒ 9 + s = 18 − 2s ⇒ 3s = 9 ⇒ s = 3 km/h.', 'For the same DISTANCE, time ratio equals the inverse of speed ratio. ''Upstream takes twice as long as downstream'' ⇒ downstream speed is twice upstream speed ⇒ (9+s) = 2(9−s). One linear equation in s.', 'Stream = s। Downstream = 9 + s, upstream = 9 − s। Same distance पर time ratio upstream:downstream = 2:1 ⇒ speeds ratio downstream:upstream = 2:1 ⇒ (9+s)/(9−s) = 2 ⇒ s = 3 km/h।', 'Same distance पर time ratio = speeds का inverse। ''Upstream में दोगुना समय'' ⇒ downstream speed upstream की दोगुनी ⇒ एक linear equation।', 'HARD', array['speed-distance','boat-stream','ratio','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '3 km/h', '3 km/h', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '4.5 km/h', '4.5 km/h', false, 'Took half of boat speed: 9/2 = 4.5. The ''2:1 time ratio'' condition sets downstream/upstream = 2, which translates to (9+s)/(9−s) = 2 ⇒ s = 3.', 'Boat speed का आधा: 9/2 = 4.5 दे दी। Condition (9+s)/(9−s) = 2 से s = 3।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '1.5 km/h', '1.5 km/h', false, 'Took 1/6 of boat speed: 9/6 = 1.5. Set the ratio equation wrong — used downstream/upstream = 3 instead of 2.', 'Boat का 1/6: 9/6 = 1.5 दे दी। Ratio 2 की जगह 3 लगाया — (9+s)/(9−s) = 3 से s = 4.5... not 1.5 either. सही 2 से s = 3।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '6 km/h', '6 km/h', false, 'Used 2/3 of boat speed: 9 × 2/3 = 6. Stream can''t equal two-thirds of boat speed while preserving a positive upstream — upstream would be 9 − 6 = 3, still valid arithmetically, but the ratio check fails: 15/3 = 5 ≠ 2.', 'Boat का 2/3: 9 × 2/3 = 6। यहाँ upstream = 3, downstream = 15, ratio = 15/3 = 5 ≠ 2 — condition fail।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 22, 'Two cars start from the same point at the same time. Car A runs at 60 km/h and Car B at 75 km/h. After 4 hours they are not on the same road — Car B''s path makes a 90° angle with Car A''s. How far apart are they?', 'दो cars एक ही point से एक साथ शुरू होती हैं। Car A 60 km/h पर, Car B 75 km/h पर। 4 घंटे बाद — वे अलग-अलग roads पर हैं, जहाँ Car B का रास्ता Car A के रास्ते से 90° का कोण बनाता है। अब वे कितनी दूर होंगी?', 'A travels 60 × 4 = 240 km; B travels 75 × 4 = 300 km. Paths are perpendicular, so separation = √(240² + 300²) = √(57,600 + 90,000) = √147,600 ≈ 384.18 km. (Accept 384 or 384.09 depending on rounding.)', 'When two paths start from the same point at right angles, the separation is the hypotenuse: √(a² + b²). This is straight-line Pythagoras applied to the two leg distances. Path-sum and path-difference shortcuts do NOT apply for non-parallel tracks.', 'A: 60 × 4 = 240 km, B: 75 × 4 = 300 km। Paths 90° पर, अतः separation = √(240² + 300²) = √(57600 + 90000) = √147600 ≈ 384 km।', 'एक ही point से 90° पर शुरू हुए रास्तों की separation hypotenuse होती है: √(a² + b²)। Non-parallel tracks में path-sum या path-difference shortcuts नहीं चलते।', 'HARD', array['speed-distance','pythagoras','right-angle-paths','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '384.09 km', '384.09 km', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '540 km', '540 km', false, 'Summed the two distances directly: 60×4 + 75×4 = 240 + 300 = 540. That''s the path length along the roads, not the straight-line separation at 90°.', 'दोनों distances जोड़ दीं: 240 + 300 = 540। यह roads पर chलने की दूरी है, 90° पर separation नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '60 km', '60 km', false, 'Subtracted the two distances: 300 − 240 = 60. Subtraction is for same-direction tracks — these are perpendicular, so use Pythagoras.', 'Distances घटाईं: 300 − 240 = 60। घटाना same-direction के लिए — ये perpendicular हैं, Pythagoras लगेगा।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '270 km', '270 km', false, 'Averaged the two distances: (240 + 300)/2 = 270. Averaging has no geometric meaning for a right-angle separation.', 'दोनों distances का average: (240 + 300)/2 = 270 — यह ज्यामितीय रूप से कोई meaning नहीं रखता।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 23, 'The ratio of speeds of two trains is 5:7. If the second train takes 3 hours less than the first to cover the same distance, and the first train''s speed is 50 km/h, find the distance.', 'दो trains की speeds का ratio 5:7 है। दूसरी train same distance पर पहली से 3 घंटे कम लेती है। पहली की speed 50 km/h हो तो distance क्या है?', 'Speeds 5:7 ⇒ second speed = 50 × 7/5 = 70 km/h. Times are inversely proportional: time ratio 7:5. Let times be 7k and 5k; difference 2k = 3 ⇒ k = 1.5. First train time = 7 × 1.5 = 10.5 h. Distance = 50 × 10.5 = 525 km. Verify with second: 70 × 7.5 = 525 ✓.', 'Speed ratio ↔ inverse time ratio (for the same distance). Parameterize both times by a common factor k, let the difference equate to the given gap, solve k, then compute the distance with either speed and its matching time.', 'Speeds 5:7 ⇒ second speed = 50 × 7/5 = 70 km/h। Times का inverse ratio 7:5। Times = 7k, 5k; difference 2k = 3 ⇒ k = 1.5। First time = 7 × 1.5 = 10.5 h। Distance = 50 × 10.5 = 525 km। Verify: 70 × 7.5 = 525 ✓।', 'Same distance पर speed ratio और time ratio inverse होते हैं। दोनों times को common factor k से parameterize करें, difference से k निकालें, फिर distance = speed × matching time।', 'HARD', array['speed-distance','ratio','time-difference','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '525 km', '525 km', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '150 km', '150 km', false, 'Used 50 × 3 = 150 treating the 3-hour gap as the first train''s total travel time. The 3-hour gap is the DIFFERENCE of times, not either train''s full time.', '50 × 3 = 150 को first train का total time मान लिया। 3-hour gap दोनों times का अंतर है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '350 km', '350 km', false, 'Used second train''s speed (70 km/h) × the gap (3 hr) × adjustment: 70 × 5 = 350. Muddled which speed/time pair should multiply.', 'Second train की speed (70) × 5 = 350 लगाया — गलत pair multiply हुआ।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '700 km', '700 km', false, 'Used the ratio-induced time pair wrong: took first train''s time = 7 h, distance = 50 × 14 = 700 (used the ratio labels 5:7 as times in hours).', 'Times को ratio labels (5, 7) से सीधे hours मान लिया: 50 × 14 = 700।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 24, 'A train overtakes two persons walking at 2 km/h and 4 km/h in the same direction in 9 seconds and 10 seconds respectively. Find the length of the train.', 'एक train same direction में चलते दो व्यक्तियों (क्रमशः 2 km/h और 4 km/h से) को 9 sec और 10 sec में overtake करती है। Train की length क्या है?', 'Let train speed = v (m/s), length = L. Walker speeds in m/s = 5/9 and 10/9. Equations: L = 9(v − 5/9) and L = 10(v − 10/9). Equate: 9v − 5 = 10v − 100/9 ⇒ v = 100/9 − 45/9 = 55/9 m/s (≈ 22 km/h). Then L = 9 × 55/9 − 5 = 55 − 5 = 50 m. Verify with the 10-s equation: 10 × (55/9 − 10/9) = 10 × 45/9 = 50 ✓.', 'Two overtakings of walkers at different speeds give two linear equations in L and v. Subtracting eliminates L, exposing v in terms of the time gap (1 s) and the relative-speed gap (5/9 m/s). Back-substitute v to get L. The walker''s speed subtracts from the train''s (same-direction relative speed).', 'Train speed = v (m/s), length = L। Walker speeds m/s में 5/9 और 10/9। Equations: L = 9(v − 5/9), L = 10(v − 10/9)। Equate: 9v − 5 = 10v − 100/9 ⇒ v = 55/9 m/s (≈ 22 km/h)। L = 9 × 55/9 − 5 = 50 m। Verify: 10 × (55/9 − 10/9) = 10 × 45/9 = 50 ✓।', 'दो walkers (अलग speeds) पर overtaking से L और v के दो linear equations। घटाने से L eliminate होकर v मिल जाता है (time gap 1 s और relative-speed gap 5/9 m/s से)। Same direction में walker की speed train से घटती है।', 'HARD', array['speed-distance','train','two-equations','relative-speed','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '50 m', '50 m', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '55 m', '55 m', false, 'Used v = 55/9 m/s ≈ 6.11 directly as the length (confused the intermediate v-value with L): 55/9 × 9 seems plausible but the correct L = 9v − 5 = 9 × 55/9 − 5 = 50.', 'Intermediate v = 55/9 m/s को ही length समझ लिया: 55/9 × 9 ≈ 55। सही: L = 9v − 5 = 50।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '44.44 m', '44.44 m', false, 'Used only the 10-second equation with walker speed 4 km/h: L = 10(v − 10/9) with an incorrect v of 20 km/h = 50/9 m/s → L = 10 × (50/9 − 10/9) = 400/9 = 44.44. Wrong v value.', 'केवल 10-sec equation लगाई: L = 10(v − 10/9) में गलत v = 50/9 m/s → 400/9 = 44.44। सही v = 55/9 m/s।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '55 m+20/9', '57.22 m', false, 'Used only the 9-second equation with walker 2 km/h: L = 9(v − 5/9) with v = 22.22 km/h ≈ 55/9 × 1.04 m/s giving ~57.22 m. Forgot the constraint from the second equation that pins v exactly to 55/9.', 'केवल 9-sec equation (walker 2 km/h) लगाई, दूसरे equation से v को pin नहीं किया: गलत v से 57.22 m मिला। सही v = 55/9 m/s।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 25, 'Find the LCM of 18 and 24.', '18 और 24 का LCM ज्ञात कीजिए।', 'Use LCM × HCF = product. HCF(18,24) = 6. LCM = 18×24/6 = 72. Therefore, answer = 72.', 'For two positive integers, HCF captures the common part and LCM captures each prime factor at its maximum power. Their product equals the product of the two numbers. Final answer is 72.', 'LCM × HCF = product लगाएँ। HCF(18,24) = 6। LCM = 18×24/6 = 72। अतः answer = 72।', 'दो positive integers में HCF common part लेता है और LCM हर prime factor की maximum power लेता है। इसलिए LCM × HCF = product। Final answer 72 है।', 'EASY', array['number-system','lcm-hcf','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '72', '72', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '6', '6', false, 'Reported HCF 6 instead of LCM. LCM is the least common multiple, not the greatest common factor.', 'HCF 6 को LCM मान लिया। LCM least common multiple होता है, greatest factor नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '42', '42', false, 'Added the numbers: 18+24=42. LCM is found from prime powers, not addition.', 'संख्याएँ जोड़ दीं: 18+24=42। LCM prime powers से निकलता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '24', '24', false, 'Picked the larger number 24. It is not divisible by both numbers in this pair.', 'बड़ी संख्या 24 चुन ली। यह दोनों numbers से divisible नहीं है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 26, 'Find the LCM of 28 and 42.', '28 और 42 का LCM ज्ञात कीजिए।', 'Use LCM × HCF = product. HCF(28,42) = 14. LCM = 28×42/14 = 84. Therefore, answer = 84.', 'For two positive integers, HCF captures the common part and LCM captures each prime factor at its maximum power. Their product equals the product of the two numbers. Final answer is 84.', 'LCM × HCF = product लगाएँ। HCF(28,42) = 14। LCM = 28×42/14 = 84। अतः answer = 84।', 'दो positive integers में HCF common part लेता है और LCM हर prime factor की maximum power लेता है। इसलिए LCM × HCF = product। Final answer 84 है।', 'EASY', array['number-system','lcm-hcf','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
