insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 28, 'Find the LCM of 45 and 75.', '45 और 75 का LCM ज्ञात कीजिए।', 'Use LCM × HCF = product. HCF(45,75) = 15. LCM = 45×75/15 = 225. Therefore, answer = 225.', 'For two positive integers, HCF captures the common part and LCM captures each prime factor at its maximum power. Their product equals the product of the two numbers. Final answer is 225.', 'LCM × HCF = product लगाएँ। HCF(45,75) = 15। LCM = 45×75/15 = 225। अतः answer = 225।', 'दो positive integers में HCF common part लेता है और LCM हर prime factor की maximum power लेता है। इसलिए LCM × HCF = product। Final answer 225 है।', 'EASY', array['number-system','lcm-hcf','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
