insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'D is the sister of E. E is the father of F. How is D related to F?', 'D, E की sister है। E, F का father है। D, F से कैसे related है?', 'Father''s sister is aunt. Trace one link at a time and answer from the asked person''s viewpoint. Therefore, answer = Aunt.', 'Blood relation questions are solved by drawing a small family chain. Keep gender and direction fixed; most wrong answers reverse the viewpoint. Final answer is Aunt.', 'Father''s sister is aunt. एक-एक link trace करें और asked person के viewpoint से relation दें। अतः answer = Aunt।', 'Blood relation questions में छोटा family chain बनता है। Gender और direction fix रखें; ज़्यादातर errors viewpoint reverse करने से होते हैं। Final answer Aunt है।', 'MEDIUM', array['blood-relations','family-tree','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
