insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'A is the father of B. B is the sister of C. How is A related to C?', 'A, B का father है। B, C की sister है। A, C से कैसे related है?', 'C is sibling of B, so A is parent of both; A is stated as father. Trace one link at a time and answer from the asked person''s viewpoint. Therefore, answer = Father.', 'Blood relation questions are solved by drawing a small family chain. Keep gender and direction fixed; most wrong answers reverse the viewpoint. Final answer is Father.', 'C is sibling of B, so A is parent of both; A is stated as father. एक-एक link trace करें और asked person के viewpoint से relation दें। अतः answer = Father।', 'Blood relation questions में छोटा family chain बनता है। Gender और direction fix रखें; ज़्यादातर errors viewpoint reverse करने से होते हैं। Final answer Father है।', 'MEDIUM', array['blood-relations','family-tree','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
